async function loadUser(id, next) {
  if (!id) return next(new Error('missing_id'));

  try {
    const user = await new Promise((resolve, reject) => {
      db.findUser(id, (err, user) => (err ? reject(err) : resolve(user)));
    });

    if (!user) return next(new Error('not_found'));

    await new Promise((resolve, reject) => {
      audit.log(user.id, err => (err ? reject(err) : resolve()));
    });

    await new Promise((resolve, reject) => {
      cache.set(user.id, user, err => (err ? reject(err) : resolve()));
    });

    return next(null, user);
  } catch (err) {
    return next(err);
  }
}
```

Keeps validation/error order:
1. `missing_id`
2. `db.findUser` error
3. `not_found`
4. `audit.log` error
5. `cache.set` error

Single DB-error-to-`next(err)` path is the `catch`. Verify callback APIs are node-style and `next` is called once.
